// // This module converts an 8-bit binary input to a 10-bit analog output in reverse proportion
module DAC (
    input [7:0] bin_input,
    output reg [9:0] analog_output
);
    always @(*) begin
        analog_output = bin_input * 1023 / 255; // scale 8-bit to 10-bit output
    end
endmodule
